import React, { useEffect, useState } from 'react';
import axios from 'axios';

function MaterialList() {
  const [material, setMaterial] = useState([]);

  useEffect(() => {
    axios
      .get('http://localhost:8081')
      .then((res) => setMaterial(res.data))
      .catch((err) => console.log(err));
  }, []);

  const handleAddMaterial = () => {
    const newMaterial = {
        matid: '', // Material ID
        name: '', // Name of the material
        description: '', // Description of the material
        unit_of_measure: '', // Unit of measure for the material
        price_per_unit: 0, // Price per unit of the material
        recent_vendor: '', // Recent vendor for the material
      };

    axios
      .post('http://localhost:8081', newMaterial)
      .then((res) => {
        // Add the newly added material to the existing material array
        setMaterial((prevMaterial) => [...prevMaterial, res.data]);
      })
      .catch((err) => console.log(err));
  };

  return (
    <div style={{ justifyContent: 'center', backgroundColor: 'blue', lineHeight: 1, padding: 50 }}>
      <div>
        <button className="btn btn-success" onClick={handleAddMaterial}>Add+</button>
        <table className="table" style={{ borderRadius: '5%', alignItems: 'center', justifyContent: 'center', backgroundColor: 'red', lineHeight: 1, padding: 50 }}>
          <thead>
            <tr>
              <th>Material ID</th>
              <th>Name</th>
              <th>Description</th>
              <th>Unit of Measure</th>
              <th>Price per Unit</th>
              <th>Recent Vendor</th>
            </tr>
          </thead>
          <tbody>
            {material.map((data, i) => {
              return (
                <tr key={i}>
                  <td>{data.matid}</td>
                  <td>{data.name}</td>
                  <td>{data.description}</td>
                  <td>{data.unit_of_measure}</td>
                  <td>{data.price_per_unit}</td>
                  <td>{data.recent_vendor}</td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default MaterialList;
